@namespace sv_67be46a5c00c4b4abceaf01d320daa64.Components.Pages.Apply

<nav class="step-indicator" aria-label="Application progress">
    <ol style="display:flex; list-style:none; padding:0; gap:0; margin:0 0 2rem;">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isCurrent = step == CurrentStep;
            var isCompleted = CompletedSteps.Contains(step);
            var isFuture = !isCurrent && !isCompleted;

            <li style="flex:1; text-align:center; position:relative;">
                @if (isCompleted)
                {
                    <button @onclick="() => OnStepClicked.InvokeAsync(step)"
                            style="background:none; border:none; cursor:pointer; width:100%; padding:0;"
                            aria-label="Go back to @StepNames[step - 1]">
                        <div style="display:flex; align-items:center; justify-content:center; margin:0 auto 0.5rem;
                                    width:2.5rem; height:2.5rem; border-radius:50%;
                                    background:#198754; color:#fff; font-size:1.1rem;">
                            ✓
                        </div>
                        <span style="font-size:0.85rem; color:#198754; font-weight:600;">@StepNames[step - 1]</span>
                    </button>
                }
                else
                {
                    <div style="display:flex; align-items:center; justify-content:center; margin:0 auto 0.5rem;
                                width:2.5rem; height:2.5rem; border-radius:50%;
                                background:@(isCurrent ? "#0d6efd" : "#dee2e6");
                                color:@(isCurrent ? "#fff" : "#adb5bd"); font-weight:700;">
                        @step
                    </div>
                    <span style="font-size:0.85rem; color:@(isCurrent ? "#0d6efd" : "#adb5bd");
                                 font-weight:@(isCurrent ? "600" : "400");">
                        @StepNames[step - 1]
                    </span>
                }
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

@namespace sv_67be46a5c00c4b4abceaf01d320daa64.Components.Pages.Apply

<div style="border:1px solid #dee2e6; border-radius:0.5rem; padding:1.25rem; margin-bottom:1rem; position:relative;">
    @if (ShowRemove)
    {
        <button @onclick="() => OnRemove.InvokeAsync()"
                style="position:absolute; top:0.75rem; right:0.75rem; background:none; border:none;
                       color:#dc3545; cursor:pointer; font-size:0.9rem;">
            ✕ Remove
        </button>
    }

    <div style="display:grid; grid-template-columns:1fr 1fr; gap:1rem;">
        <div>
            <label>Company Name</label>
            <input type="text" value="@Entry.Company"
                   @onchange="e => Update(Entry with { Company = (string?)e.Value ?? string.Empty })"
                   placeholder="Company name" style="width:100%; padding:0.4rem; border:1px solid #ced4da; border-radius:0.25rem;" />
        </div>
        <div>
            <label>Job Title</label>
            <input type="text" value="@Entry.Title"
                   @onchange="e => Update(Entry with { Title = (string?)e.Value ?? string.Empty })"
                   placeholder="Job title" style="width:100%; padding:0.4rem; border:1px solid #ced4da; border-radius:0.25rem;" />
        </div>
        <div>
            <label>Start Date</label>
            <input type="date" value="@Entry.StartDate.ToString("yyyy-MM-dd")"
                   @onchange="e => Update(Entry with { StartDate = DateTime.Parse((string?)e.Value ?? DateTime.Today.ToString("yyyy-MM-dd")) })"
                   style="width:100%; padding:0.4rem; border:1px solid #ced4da; border-radius:0.25rem;" />
        </div>
        <div>
            <label style="display:flex; align-items:center; gap:0.5rem;">
                <span>End Date</span>
                <input type="checkbox" checked="@_isCurrent"
                       @onchange="ToggleCurrent" />
                <span style="font-size:0.85rem; color:#6c757d;">Current position</span>
            </label>
            @if (!_isCurrent)
            {
                <input type="date" value="@(Entry.EndDate?.ToString("yyyy-MM-dd") ?? string.Empty)"
                       @onchange="e => Update(Entry with { EndDate = DateTime.TryParse((string?)e.Value, out var d) ? d : null })"
                       style="width:100%; padding:0.4rem; border:1px solid #ced4da; border-radius:0.25rem;" />
            }
        </div>
    </div>

    <div style="margin-top:1rem;">
        <label>Description</label>
        <textarea value="@Entry.Description"
                  @onchange="e => Update(Entry with { Description = (string?)e.Value ?? string.Empty })"
                  rows="3" placeholder="Describe your responsibilities and achievements"
                  style="width:100%; padding:0.4rem; border:1px solid #ced4da; border-radius:0.25rem; resize:vertical;"></textarea>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback<WorkEntry> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool _isCurrent;

    protected override void OnParametersSet() => _isCurrent = Entry.EndDate is null;

    private void Update(WorkEntry updated) => OnChanged.InvokeAsync(updated);

    private void ToggleCurrent(ChangeEventArgs e)
    {
        _isCurrent = (bool)(e.Value ?? false);
        Update(Entry with { EndDate = _isCurrent ? null : DateTime.Today });
    }
}

@namespace sv_67be46a5c00c4b4abceaf01d320daa64.Components.Pages.Apply

