    </button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntry> Entries { get; set; } = [];
    [Parameter] public EventCallback<List<WorkEntry>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _error;

    private void UpdateEntry(int index, WorkEntry entry)
    {
        Entries[index] = entry;
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntry(string.Empty, string.Empty, DateTime.Today, null, string.Empty));
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1) Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        _error = null;
        if (Entries.Any(e => string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title)))
        {
            _error = "Each position requires at least a company name and job title.";
            return;
        }
        await OnNext.InvokeAsync(Entries);
    }
}

