@namespace sv_67be46a5c00c4b4abceaf01d320daa64.Components.Pages.Apply

@if (_submitted)
{
    <div style="text-align:center; padding:3rem 1rem;">
        <div style="font-size:3rem; margin-bottom:1rem;">✅</div>
        <h2 style="color:#198754;">Application Submitted!</h2>
        <p style="font-size:1.1rem; color:#495057;">
            Your application ID is <strong>#@_applicationId</strong>
        </p>
        <p style="color:#6c757d;">We'll be in touch soon. Thank you for applying!</p>
    </div>
}
else
{
    <h3>Review &amp; Submit</h3>

    @* Personal Info Section *@
    <div style="border:1px solid #dee2e6; border-radius:0.5rem; padding:1.25rem; margin-bottom:1rem;">
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:0.75rem;">
            <h4 style="margin:0;">Personal Information</h4>
            <button @onclick='() => OnEdit.InvokeAsync(1)' style="background:none; border:none; color:#0d6efd; cursor:pointer; font-size:0.9rem;">Edit</button>
        </div>
        <div style="display:grid; grid-template-columns:1fr 1fr; gap:0.5rem; color:#495057;">
            <div><strong>Name:</strong> @Personal.FullName</div>
            <div><strong>Email:</strong> @Personal.Email</div>
            <div><strong>Phone:</strong> @Personal.Phone</div>
            <div><strong>Address:</strong> @Personal.Address</div>
        </div>
    </div>

    @* Work History Section *@
    <div style="border:1px solid #dee2e6; border-radius:0.5rem; padding:1.25rem; margin-bottom:1rem;">
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:0.75rem;">
            <h4 style="margin:0;">Work History</h4>
            <button @onclick='() => OnEdit.InvokeAsync(2)' style="background:none; border:none; color:#0d6efd; cursor:pointer; font-size:0.9rem;">Edit</button>
        </div>
        @foreach (var entry in WorkEntries)
        {
            <div style="padding:0.5rem 0; border-bottom:1px solid #f0f0f0; color:#495057;">
                <strong>@entry.Title</strong> at @entry.Company<br />
                <span style="font-size:0.85rem; color:#6c757d;">
                    @entry.StartDate.ToString("MMM yyyy") – @(entry.EndDate?.ToString("MMM yyyy") ?? "Present")
                </span>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p style="margin:0.25rem 0 0; font-size:0.9rem;">@entry.Description</p>
                }
            </div>
        }
    </div>

    @* References Section *@
    <div style="border:1px solid #dee2e6; border-radius:0.5rem; padding:1.25rem; margin-bottom:1rem;">
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:0.75rem;">
            <h4 style="margin:0;">References</h4>
            <button @onclick='() => OnEdit.InvokeAsync(3)' style="background:none; border:none; color:#0d6efd; cursor:pointer; font-size:0.9rem;">Edit</button>
        </div>
        @foreach (var r in References)
        {
            <div style="padding:0.5rem 0; border-bottom:1px solid #f0f0f0; color:#495057;">
                <strong>@r.Name</strong> (@r.Relationship)<br />
                <span style="font-size:0.85rem; color:#6c757d;">@r.Email · @r.Phone</span>
            </div>
        }
    </div>

    @* Cover Letter Section *@
    <div style="border:1px solid #dee2e6; border-radius:0.5rem; padding:1.25rem; margin-bottom:1.5rem;">
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:0.75rem;">
            <h4 style="margin:0;">Cover Letter</h4>
            <button @onclick='() => OnEdit.InvokeAsync(4)' style="background:none; border:none; color:#0d6efd; cursor:pointer; font-size:0.9rem;">Edit</button>
        </div>
        <p style="white-space:pre-wrap; color:#495057; margin:0;">@CoverLetter</p>
    </div>

    @if (!string.IsNullOrEmpty(_error))
    {
        <div style="color:#dc3545; background:#f8d7da; padding:0.75rem; border-radius:0.25rem; margin-bottom:1rem;">
            @_error
        </div>
    }

    <div style="display:flex; justify-content:space-between;">
        <button @onclick="() => OnBack.InvokeAsync()"
                style="padding:0.5rem 1.5rem; background:#6c757d; color:#fff; border:none;
                       border-radius:0.25rem; cursor:pointer;">
            ← Back
        </button>
        <button @onclick="HandleSubmit" disabled="@_submitting"
                style="padding:0.5rem 2rem; background:#198754; color:#fff; border:none;
                       border-radius:0.25rem; cursor:pointer; font-weight:600;">
            @(_submitting ? "Submitting..." : "Submit Application")
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfo Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntry> WorkEntries { get; set; } = [];
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = [];
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = string.Empty;
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public IApplicationService ApplicationService { get; set; } = default!;

    private bool _submitting;
    private bool _submitted;
    private int _applicationId;
    private string? _error;

    private async Task HandleSubmit()
    {
        _submitting = true;
        _error = null;
        try
        {
            var application = new JobApplication(
                Personal,
                new WorkHistory(WorkEntries),
                References,
                CoverLetter);
            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _error = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _submitting = false;
        }
    }
}

