@namespace sv_67be46a5c00c4b4abceaf01d320daa64.Components.Pages.Apply

<h3>Personal Information</h3>

@if (!string.IsNullOrEmpty(_error))
{
    <div style="color:#dc3545; background:#f8d7da; padding:0.75rem; border-radius:0.25rem; margin-bottom:1rem;">
        @_error
    </div>
}

<div style="display:grid; grid-template-columns:1fr 1fr; gap:1rem; margin-bottom:1.5rem;">
    <div>
        <label>Full Name <span style="color:#dc3545;">*</span></label>
        <input type="text" value="@Model.FullName"
               @onchange="e => Model = Model with { FullName = (string?)e.Value ?? string.Empty }"
               placeholder="John Doe"
               style="width:100%; padding:0.5rem; border:1px solid #ced4da; border-radius:0.25rem;" />
    </div>
    <div>
        <label>Email <span style="color:#dc3545;">*</span></label>
        <input type="email" value="@Model.Email"
               @onchange="e => Model = Model with { Email = (string?)e.Value ?? string.Empty }"
               placeholder="john@example.com"
               style="width:100%; padding:0.5rem; border:1px solid #ced4da; border-radius:0.25rem;" />
    </div>
    <div>
        <label>Phone <span style="color:#dc3545;">*</span></label>
        <input type="tel" value="@Model.Phone"
               @onchange="e => Model = Model with { Phone = (string?)e.Value ?? string.Empty }"
               placeholder="(555) 123-4567"
               style="width:100%; padding:0.5rem; border:1px solid #ced4da; border-radius:0.25rem;" />
    </div>
    <div>
        <label>Address <span style="color:#dc3545;">*</span></label>
        <input type="text" value="@Model.Address"
               @onchange="e => Model = Model with { Address = (string?)e.Value ?? string.Empty }"
               placeholder="123 Main St, City, State 12345"
               style="width:100%; padding:0.5rem; border:1px solid #ced4da; border-radius:0.25rem;" />
    </div>
</div>

<div style="display:flex; justify-content:flex-end;">
    <button @onclick="HandleNext" disabled="@_validating"
            style="padding:0.5rem 1.5rem; background:#0d6efd; color:#fff; border:none;
                   border-radius:0.25rem; cursor:pointer;">
        @(_validating ? "Validating..." : "Next →")
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfo Model { get; set; } = default!;
    [Parameter] public EventCallback<PersonalInfo> OnNext { get; set; }
    [Parameter] public IApplicationService ApplicationService { get; set; } = default!;

    private string? _error;
    private bool _validating;

    private async Task HandleNext()
    {
        _error = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) || string.IsNullOrWhiteSpace(Model.Email)
            || string.IsNullOrWhiteSpace(Model.Phone) || string.IsNullOrWhiteSpace(Model.Address))
        {
            _error = "All fields are required.";
            return;
        }

        _validating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                _error = "Please enter a valid email address.";
                return;
            }
            await OnNext.InvokeAsync(Model);
        }
        finally
        {
            _validating = false;
        }
    }
}

