toolArgs.file_text:
@namespace sv_67be46a5c00c4b4abceaf01d320daa64.Components.Pages.Apply

<h3>Work History</h3>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <h5 style="margin-top:1rem; color:#495057;">Position @(index + 1)</h5>
    <WorkEntryForm Entry="Entries[index]"
                   ShowRemove="Entries.Count > 1"
                   OnChanged="entry => UpdateEntry(index, entry)"
                   OnRemove="() => RemoveEntry(index)" />
}

<button @onclick="AddEntry"
        style="padding:0.4rem 1rem; background:none; border:1px dashed #0d6efd; color:#0d6efd;
               border-radius:0.25rem; cursor:pointer; margin-bottom:1.5rem;">
    + Add Another Position
</button>

@if (!string.IsNullOrEmpty(_error))
{
    <div style="color:#dc3545; background:#f8d7da; padding:0.75rem; border-radius:0.25rem; margin-bottom:1rem;">
        @_error
    </div>
}

<div style="display:flex; justify-content:space-between;">
    <button @onclick="() => OnBack.InvokeAsync()"
            style="padding:0.5rem 1.5rem; background:#6c757d; color:#fff; border:none;
                   border-radius:0.25rem; cursor:pointer;">
        ← Back
    </button>
    <button @onclick="HandleNext"
            style="padding:0.5rem 1.5rem; background:#0d6efd; color:#fff; border:none;
                   border-radius:0.25rem; cursor:pointer;">
        Next →
    </button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntry> Entries { get; set; } = [];
    [Parameter] public EventCallback<List<WorkEntry>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _error;

    private void UpdateEntry(int index, WorkEntry entry)
    {
        Entries[index] = entry;
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntry(string.Empty, string.Empty, DateTime.Today, null, string.Empty));
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1) Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        _error = null;
        if (Entries.Any(e => string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title)))
        {
            _error = "Each position requires at least a company name and job title.";
            return;
        }
        await OnNext.InvokeAsync(Entries);
    }
}

