                   OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button @onclick="AddReference"
            style="padding:0.4rem 1rem; background:none; border:1px dashed #0d6efd; color:#0d6efd;
                   border-radius:0.25rem; cursor:pointer; margin-bottom:1.5rem;">
        + Add Reference
    </button>
}

@if (!string.IsNullOrEmpty(_error))
{
    <div style="color:#dc3545; background:#f8d7da; padding:0.75rem; border-radius:0.25rem; margin-bottom:1rem;">
        @_error
    </div>
}

<div style="display:flex; justify-content:space-between;">
    <button @onclick="() => OnBack.InvokeAsync()"
            style="padding:0.5rem 1.5rem; background:#6c757d; color:#fff; border:none;
                   border-radius:0.25rem; cursor:pointer;">
        ← Back
    </button>
    <button @onclick="HandleNext"
            style="padding:0.5rem 1.5rem; background:#0d6efd; color:#fff; border:none;
                   border-radius:0.25rem; cursor:pointer;">
        Next →
    </button>
</div>

@code {
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = [];
    [Parameter] public EventCallback<List<Reference>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _error;

    private void UpdateReference(int index, Reference reference)
    {
        References[index] = reference;
    }

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new Reference(string.Empty, string.Empty, string.Empty, string.Empty));
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2) References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        _error = null;
        if (References.Count < 2)
        {
            _error = "At least 2 references are required.";
            return;
        }
        if (References.Any(r => string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Email)))
        {
            _error = "Each reference requires at least a name and email.";
            return;
        }
        await OnNext.InvokeAsync(References);
    }
}

