@namespace sv_67be46a5c00c4b4abceaf01d320daa64.Components.Pages.Apply

<h3>Cover Letter</h3>

<div style="margin-bottom:1rem;">
    <textarea @oninput="OnInput" value="@CoverLetter" rows="12"
              placeholder="Write your cover letter here..."
              style="width:100%; padding:0.75rem; border:1px solid #ced4da; border-radius:0.25rem;
                     resize:vertical; font-size:1rem; line-height:1.6;"></textarea>
    <div style="text-align:right; font-size:0.85rem; color:@(CoverLetter.Length > MaxLength ? "#dc3545" : "#6c757d");">
        @CoverLetter.Length / @MaxLength characters
    </div>
</div>

@if (!string.IsNullOrEmpty(_error))
{
    <div style="color:#dc3545; background:#f8d7da; padding:0.75rem; border-radius:0.25rem; margin-bottom:1rem;">
        @_error
    </div>
}

<div style="display:flex; justify-content:space-between;">
    <button @onclick="() => OnBack.InvokeAsync()"
            style="padding:0.5rem 1.5rem; background:#6c757d; color:#fff; border:none;
                   border-radius:0.25rem; cursor:pointer;">
        ← Back
    </button>
    <button @onclick="HandleNext"
            style="padding:0.5rem 1.5rem; background:#0d6efd; color:#fff; border:none;
                   border-radius:0.25rem; cursor:pointer;">
        Next →
    </button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter, EditorRequired] public string CoverLetter { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _error;

    private void OnInput(ChangeEventArgs e)
    {
        CoverLetter = (string?)e.Value ?? string.Empty;
    }

    private async Task HandleNext()
    {
        _error = null;
        if (CoverLetter.Length > MaxLength)
        {
            _error = $"Cover letter cannot exceed {MaxLength} characters.";
            return;
        }
        await OnNext.InvokeAsync(CoverLetter);
    }
}

