    private void OnTitleChanged(ChangeEventArgs e) =>
        Update(Entry with { Title = (string?)e.Value ?? string.Empty });

    private void OnStartDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse((string?)e.Value, out var d))
            Update(Entry with { StartDate = d });
    }

    private void OnEndDateChanged(ChangeEventArgs e)
    {
        DateTime? endDate = DateTime.TryParse((string?)e.Value, out var d) ? d : null;
        Update(Entry with { EndDate = endDate });
    }

    private void OnDescriptionChanged(ChangeEventArgs e) =>
        Update(Entry with { Description = (string?)e.Value ?? string.Empty });

    private void ToggleCurrent(ChangeEventArgs e)
    {
        _isCurrent = (bool)(e.Value ?? false);
        Update(Entry with { EndDate = _isCurrent ? null : DateTime.Today });
    }
}

